import {
  Component,
  Element,
  State,
  Event,
  EventEmitter,
  Method,
  Prop,
  h
} from '@stencil/core';
import {
  getHostAttributes,
  getSpreadableAttributes,
  setDefaultHostAttributes,
  setStyleAttribute
} from '@src/utils/kds-utils/attributes/attributeUtils';
import { registerAttributeObserver } from '@src/utils/kds-utils/registerObserver';


interface KdsCheckboxHostElement extends HTMLInputElement {
  nativeElement: HTMLInputElement;
}

/**
 * Checkboxes should be used when a user needs to make a selection or select multiple options within a list. They can be used to opt in or out of something.
 *
 * > **Note:** `<kds-checkbox />` is a [primitive web component](primitives/) that accepts all props listed below and any attributes prefixed with `inner-`.
 * `inner-*` attributes are stripped of their `inner-` prefix and placed onto a rendered native `<input type="checkbox">` element.
 *
 * */
@Component({
  tag: 'kds-checkbox',
  styleUrl: 'kds-checkbox.css',
  shadow: false
})
export class KdsCheckBox {
  @Element() hostEl: KdsCheckboxHostElement;

  /** Sets the color palette. */
    // prettier-ignore
  @Prop() readonly palette: 'neutral' | 'brand' | 'accent' | 'positive' | 'negative' | 'informative' | 'callout' | 'special' = 'brand';
  /** Applies the inverse color styling. */
  @Prop() readonly inverse: boolean = false;
  /** Sets the color kind. */
  @Prop() readonly kind: 'dominant' | 'prominent' = 'dominant';
  /** Takes focus when the form is presented. */
  @Prop() readonly autofocus: boolean;
  /** Indicates currently-selected item. */
  @Prop({ mutable: true }) checked?: boolean = false;
  /** Disables if present. */
  @Prop() readonly disabled?: boolean = false;
  /** Sets indeterminate state. */
  @Prop({ mutable: true }) indeterminate?: boolean = false;
  /** Sets the name. */
  @Prop() readonly name?: string;
  /** Requires value before submission. */
  @Prop() readonly required?: boolean;
  /** Contains the current value. */
  @Prop({ mutable: true }) value?: string | string[] | number;
  /** Applies the compact size. */
  @Prop() readonly compact?: boolean = false;
  /** Sets a class to the rendered `<input type="checkbox">`. */
  @Prop() readonly checkboxClass?: string;

  @State() innerAttrs: any;

  private observer: MutationObserver;
  private checkboxElement!: HTMLInputElement;

  /**
   * Emits when the component has been loaded.
   * Event's `detail` contains a reference to the inner input element.
   */
  @Event() ready: EventEmitter<HTMLInputElement>;

  componentWillLoad() {
    this.innerAttrs = getHostAttributes(this.hostEl);
    setDefaultHostAttributes(this.hostEl);
    this.observer = registerAttributeObserver(this);
  }

  componentDidLoad() {
    this.observer.observe(this.hostEl, { attributes: true });
    this.ready.emit(this.checkboxElement);
    this.hostEl.nativeElement = this.checkboxElement;
  }

  disconnectedCallback() {
    this.observer && this.observer.disconnect();
  }

  /**
   * Returns the native `<input>` element used under the hood.
   */
  @Method()
  getNativeElement(): Promise<HTMLInputElement> {
    return Promise.resolve(this.checkboxElement!);
  }

  private onChange = (ev: Event) => {
    const input = ev.target as HTMLInputElement | null;
    if (input) {
      this.checked = input.checked;
      this.indeterminate = input.indeterminate;
    }
  };

  render() {
    return (
      <input
        {...getSpreadableAttributes(this.innerAttrs)}
        autofocus={this.autofocus}
        checked={this.checked}
        disabled={this.disabled}
        indeterminate={this.indeterminate}
        name={this.name}
        required={this.required}
        onChange={this.onChange}
        class={{
          'kds-Checkbox': true,
          'kds-Checkbox--compact': this.compact,
          [`palette-${this.palette}`]: true,
          [`kind-${this.kind}`]: true,
          [this.checkboxClass]: Boolean(this.checkboxClass),
          'as-inverse': this.inverse,
          control: true,
          interactive: true
        }}
        ref={(el: HTMLInputElement) => {
          this.checkboxElement = el;
          setStyleAttribute(el, this.innerAttrs);
        }}
        type='checkbox'
        value={this.value}
      />
    );
  }
}
